/**
 * WordPress Media Uploader Handler
 * Handles image selection and upload functionality using WordPress Media Library
 */
(function($) {
    'use strict';

    let mediaFrame = null;
    let activeContext = null;

    /**
     * Initialize media uploader functionality when document is ready
     */
    $(document).ready(function() {
        initializeMediaUploader();
    });

    /**
     * Initialize the media uploader event handlers
     */
    function initializeMediaUploader() {
        $(document)
            .off('click.dapfforwcMediaUploader', '.image-options .term-option')
            .on('click.dapfforwcMediaUploader', '.image-options .term-option', handleTermOptionClick)
            .off('click.dapfforwcMediaUploader', '.upload-image-button')
            .on('click.dapfforwcMediaUploader', '.upload-image-button', handleImageUploadClick)
            .off('click.dapfforwcMediaUploader', '.remove-image-button')
            .on('click.dapfforwcMediaUploader', '.remove-image-button', handleRemoveImageClick);
    }

    /**
     * Handle click event for the full image card
     * @param {Event} event - The click event object
     */
    function handleTermOptionClick(event) {
        const $target = $(event.target);

        if ($target.closest('.remove-image-button').length) {
            return;
        }

        event.preventDefault();

        openMediaFrameForTermOption($(this));
    }

    /**
     * Handle click event for image upload buttons
     * @param {Event} event - The click event object
     */
    function handleImageUploadClick(event) {
        event.preventDefault();
        event.stopPropagation();

        openMediaFrameForTermOption($(this).closest('.term-option'));
    }

    /**
     * Handle click event for image removal buttons
     * @param {Event} event - The click event object
     */
    function handleRemoveImageClick(event) {
        event.preventDefault();
        event.stopPropagation();

        const $button = $(this);
        const $termOption = $button.closest('.term-option');
        const $inputField = $termOption.find('input[type="hidden"]').first();
        const $imgpreview = $termOption.find('img').first();

        if (!$inputField.length) {
            console.warn('No input field found for remove button');
            return;
        }

        updateImageField($termOption, $inputField, $imgpreview, '');
    }

    /**
     * Resolve a term option card into upload field context and open the uploader
     * @param {jQuery} $termOption - The image option container
     */
    function openMediaFrameForTermOption($termOption) {
        const $inputField = $termOption.find('input[type="hidden"]').first();
        const $imgpreview = $termOption.find('img').first();

        if (!$inputField.length) {
            console.warn('No input field found for upload target');
            return;
        }

        openMediaFrame($inputField, $imgpreview, $termOption);
    }

    /**
     * Open WordPress media frame for image selection
     * @param {jQuery} $inputField - The input field to populate with selected image URL
     */
    function openMediaFrame($inputField, $imgpreview, $termOption) {
        if (typeof wp === 'undefined' || !wp.media) {
            console.error('WordPress media uploader is not available');
            return;
        }

        activeContext = {
            $inputField: $inputField,
            $imgpreview: $imgpreview,
            $termOption: $termOption
        };

        if (!mediaFrame) {
            mediaFrame = wp.media.frames.imageUploadFrame = wp.media({
                title: 'Select or Upload an Image',
                button: {
                    text: 'Use this Image'
                },
                multiple: false,
                library: {
                    type: 'image'
                }
            });

            mediaFrame.on('select', handleMediaSelection);
        }

        // Open the media frame
        mediaFrame.open();
    }

    /**
     * Handle media selection from WordPress media library
     */
    function handleMediaSelection() {
        try {
            if (!mediaFrame || !activeContext) {
                return;
            }

            const selection = mediaFrame.state().get('selection');
            const selectedImage = selection.first();

            if (selectedImage) {
                const imageData = selectedImage.toJSON();

                // Validate image data
                if (imageData && imageData.url) {
                    updateImageField(
                        activeContext.$termOption,
                        activeContext.$inputField,
                        activeContext.$imgpreview,
                        imageData.url
                    );
                } else {
                    console.error('Invalid image data received');
                }
            }
        } catch (error) {
            console.error('Error handling media selection:', error);
        }
    }

    /**
     * Update the hidden field, preview image and remove button state
     * @param {jQuery} $termOption - The image option container
     * @param {jQuery} $inputField - The input field to populate
     * @param {jQuery} $imgpreview - The img element to update
     * @param {string} imageUrl - The selected image URL
     */
    function updateImageField($termOption, $inputField, $imgpreview, imageUrl) {
        const normalizedUrl = imageUrl || '';
        const fallbackImage = getFallbackImage($termOption);

        $inputField.val(normalizedUrl);
        $termOption.toggleClass('has-custom-image', normalizedUrl !== '');

        if ($imgpreview.length) {
            $imgpreview.attr('src', normalizedUrl || fallbackImage);
        }

        toggleRemoveButton($termOption, normalizedUrl !== '');
        notifyFieldChange($inputField);
    }

    /**
     * Resolve the preview image shown when no custom image is set
     * @param {jQuery} $termOption - The image option container
     * @returns {string}
     */
    function getFallbackImage($termOption) {
        const defaultImage = ($termOption.attr('data-default-image') || '').trim();
        const placeholderImage = ($termOption.attr('data-placeholder-image') || '').trim();

        return defaultImage || placeholderImage;
    }

    /**
     * Toggle remove button visibility for the current term option
     * @param {jQuery} $termOption - The image option container
     * @param {boolean} hasCustomImage - Whether a custom image is currently set
     */
    function toggleRemoveButton($termOption, hasCustomImage) {
        const $removeButton = $termOption.find('.remove-image-button').first();
        if ($removeButton.length) {
            $removeButton.toggleClass('is-hidden', !hasCustomImage);
        }
    }

    /**
     * Notify native listeners that the hidden field changed
     * @param {jQuery} $inputField - The field to notify from
     */
    function notifyFieldChange($inputField) {
        const inputElement = $inputField.get(0);

        if (!inputElement) {
            return;
        }

        inputElement.dispatchEvent(new Event('input', {
            bubbles: true
        }));
        inputElement.dispatchEvent(new Event('change', {
            bubbles: true
        }));
    }

})(jQuery);
